#include <stdio.h>

typedef struct { int code; const char* msg; } Response;

void handle(Response r) {
    if (r.code == 200) printf("Success: %s\n", r.msg);
    else printf("Error\n");
}

#include <omp.h>
#include <stdio.h>

void process(double* data, int size) {
    #pragma omp parallel for
    for(int i = 0; i < size; i++) {
        data[i] *= 2.0;
    }
}

